classdef HeightSweepEquivalence
    %HEIGHTSWEEPEQUIVALENCE Compare optimized and reference cost volumes.
    %
    % Finite-mask equality and cost agreement are assessed separately from
    % discrete label selection. Label disagreements are permitted only where
    % the reference best/second-best margin is within the configured tie
    % tolerance. This keeps numerical drift distinct from a harmless change
    % in the winner of an effectively tied discrete minimum.
    %
    % Traceability: algo/main.tex Secs. 11.2--11.4 and 14.6;
    % implementation plan Stage C0.

    methods (Static)
        function report = compare(reference, candidate, options)
            arguments
                reference (:, :, :) {mustBeNumeric, mustBeReal}
                candidate (:, :, :) {mustBeNumeric, mustBeReal, ...
                    mustMatchCostSize(candidate, reference)}
                options.CostTolerance (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-10
                options.TieTolerance (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-9
            end

            referenceFinite = isfinite(reference);
            candidateFinite = isfinite(candidate);
            finiteMaskEqual = isequal(referenceFinite, candidateFinite);
            jointlyFinite = referenceFinite & candidateFinite;
            delta = abs(double(reference(jointlyFinite)) ...
                - double(candidate(jointlyFinite)));
            if isempty(delta)
                maximumAbsoluteCostDifference = 0;
            else
                maximumAbsoluteCostDifference = max(delta);
            end

            referenceSelection = HeightSweepEquivalence.select(reference);
            candidateSelection = HeightSweepEquivalence.select(candidate);
            comparable = referenceSelection.Valid ...
                & candidateSelection.Valid;
            stable = comparable ...
                & referenceSelection.Margin > options.TieTolerance;
            labelAgreement = referenceSelection.Index ...
                == candidateSelection.Index;
            stableDisagreement = stable & ~labelAgreement;
            tiedDisagreement = comparable & ~stable & ~labelAgreement;

            report = struct( ...
                "FiniteMaskEqual", finiteMaskEqual, ...
                "FiniteMaskMismatchCount", ...
                nnz(xor(referenceFinite, candidateFinite)), ...
                "JointFiniteCount", nnz(jointlyFinite), ...
                "MaximumAbsoluteCostDifference", ...
                maximumAbsoluteCostDifference, ...
                "CostTolerance", options.CostTolerance, ...
                "CostWithinTolerance", ...
                maximumAbsoluteCostDifference <= options.CostTolerance, ...
                "TieTolerance", options.TieTolerance, ...
                "ComparablePixelCount", nnz(comparable), ...
                "StablePixelCount", nnz(stable), ...
                "StableLabelDisagreementCount", nnz(stableDisagreement), ...
                "TiedLabelDisagreementCount", nnz(tiedDisagreement), ...
                "StableLabelAgreementFraction", ...
                HeightSweepEquivalence.fraction( ...
                nnz(stable & labelAgreement), nnz(stable)), ...
                "ReferenceLabelIndex", referenceSelection.Index, ...
                "CandidateLabelIndex", candidateSelection.Index, ...
                "ReferenceMargin", referenceSelection.Margin, ...
                "CandidateMargin", candidateSelection.Margin, ...
                "Pass", finiteMaskEqual ...
                && maximumAbsoluteCostDifference <= options.CostTolerance ...
                && ~any(stableDisagreement, "all"), ...
                "Definition", ...
                "exact finite masks; bounded cost drift; stable WTA labels agree");
        end

        function report = comparePrecision(reference, candidate, options)
            %COMPAREPRECISION Gate a reduced-precision dense result.
            % Geometry-derived endpoints remain double; costs and WTA state
            % may use single. Traceability: implementation plan Stage C3.

            arguments
                reference (1, 1) struct
                candidate (1, 1) struct
                options.StableMargin (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-4
                options.MaximumMedianEndpointDeltaPixels (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.01
                options.MaximumP99EndpointDeltaPixels (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.05
            end

            validMaskEqual = isequal(reference.Valid, candidate.Valid);
            comparable = reference.Valid & candidate.Valid;
            labelAgreement = reference.LabelIndex ...
                == candidate.LabelIndex;
            stable = comparable & isfinite(reference.CostMargin) ...
                & double(reference.CostMargin) > options.StableMargin;
            stableDisagreement = stable & ~labelAgreement;
            lowerMarginDisagreement = comparable & ~stable ...
                & ~labelAgreement;

            rp = reference.CorrespondenceXY;
            cp = candidate.CorrespondenceXY;
            endpointValid = comparable ...
                & all(isfinite(rp), 3) & all(isfinite(cp), 3);
            dx = double(cp(:, :, 1)) - double(rp(:, :, 1));
            dy = double(cp(:, :, 2)) - double(rp(:, :, 2));
            endpointDelta = hypot(dx(endpointValid), dy(endpointValid));
            if isempty(endpointDelta)
                medianEndpointDelta = NaN;
                p99EndpointDelta = NaN;
            else
                medianEndpointDelta = median(endpointDelta);
                p99EndpointDelta = ...
                    HeightSweepEquivalence.percentile(endpointDelta, 0.99);
            end
            heightDelta = abs(double(candidate.HeightMetres(comparable)) ...
                - double(reference.HeightMetres(comparable)));
            if isempty(heightDelta)
                medianHeightDelta = NaN;
                maximumHeightDelta = NaN;
            else
                medianHeightDelta = median(heightDelta);
                maximumHeightDelta = max(heightDelta);
            end

            endpointPass = isfinite(medianEndpointDelta) ...
                && medianEndpointDelta ...
                <= options.MaximumMedianEndpointDeltaPixels ...
                && p99EndpointDelta ...
                <= options.MaximumP99EndpointDeltaPixels;
            report = struct( ...
                "ValidMaskEqual", validMaskEqual, ...
                "ValidMaskMismatchCount", ...
                nnz(xor(reference.Valid, candidate.Valid)), ...
                "FalseValidCount", ...
                nnz(candidate.Valid & ~reference.Valid), ...
                "ComparablePixelCount", nnz(comparable), ...
                "StableMargin", options.StableMargin, ...
                "StablePixelCount", nnz(stable), ...
                "StableLabelDisagreementCount", ...
                nnz(stableDisagreement), ...
                "LowerMarginLabelDisagreementCount", ...
                nnz(lowerMarginDisagreement), ...
                "StableLabelAgreementFraction", ...
                HeightSweepEquivalence.fraction( ...
                nnz(stable & labelAgreement), nnz(stable)), ...
                "EndpointComparablePixelCount", nnz(endpointValid), ...
                "MedianEndpointDeltaPixels", medianEndpointDelta, ...
                "P99EndpointDeltaPixels", p99EndpointDelta, ...
                "MaximumMedianEndpointDeltaPixels", ...
                options.MaximumMedianEndpointDeltaPixels, ...
                "MaximumP99EndpointDeltaPixels", ...
                options.MaximumP99EndpointDeltaPixels, ...
                "MedianAbsoluteHeightDeltaMetres", medianHeightDelta, ...
                "MaximumAbsoluteHeightDeltaMetres", maximumHeightDelta, ...
                "Pass", validMaskEqual ...
                && ~any(stableDisagreement, "all") && endpointPass, ...
                "Definition", ...
                "exact masks and stable labels; bounded endpoint delta");
        end
    end

    methods (Static, Access = private)
        function selection = select(cost)
            [nr, nc, nl] = size(cost);
            c = reshape(double(cost), nr .* nc, nl);
            c(~isfinite(c)) = Inf;
            [ordered, order] = sort(c, 2, "ascend");
            best = ordered(:, 1);
            valid = isfinite(best);
            index = order(:, 1);
            index(~valid) = 0;
            margin = nan(nr .* nc, 1);
            if nl >= 2
                second = ordered(:, 2);
                hasSecond = valid & isfinite(second);
                margin(hasSecond) = second(hasSecond) - best(hasSecond);
            end
            selection = struct( ...
                "Valid", reshape(valid, nr, nc), ...
                "Index", reshape(index, nr, nc), ...
                "Margin", reshape(margin, nr, nc));
        end

        function value = fraction(numerator, denominator)
            if denominator == 0
                value = NaN;
            else
                value = numerator ./ denominator;
            end
        end


        function value = percentile(x, fraction)
            x = sort(x(:));
            q = 1 + (numel(x) - 1) .* fraction;
            lo = floor(q);
            hi = ceil(q);
            if lo == hi
                value = x(lo);
            else
                value = x(lo) .* (hi - q) + x(hi) .* (q - lo);
            end
        end
    end
end

function mustMatchCostSize(candidate, reference)
if ~isequal(size(candidate), size(reference))
    error("HeightSweepEquivalence:SizeMismatch", ...
        "Reference and candidate cost volumes must have identical sizes.");
end
end
